// OJ-Referral-Optin-Sink (OJ-FUNNEL T5, 2026-07-19)
// refer.html form -> referral_optin event. Referral-note email queued for the
// send engine (blocked on Resend key rotation; the queue drains automatically after).
const OJ_URL='https://wwacjhkpuaiijbkqnhsi.supabase.co';
const OJ_KEY='eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Ind3YWNqaGtwdWFpaWpia3FuaHNpIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3ODgwODQyNSwiZXhwIjoyMDk0Mzg0NDI1fQ.I92OcFBQ9lxs4hFH3Q_rWYup2bULHuL3a2rqeEb1xf0';
const H={apikey:OJ_KEY,Authorization:'Bearer '+OJ_KEY,'Content-Type':'application/json'};
const b=$input.item.json.body||$input.item.json||{};
const email=(b.email||'').toString().toLowerCase().slice(0,200);
const name=(b.name||'').toString().slice(0,120);
if(!email||!email.includes('@')) return [{json:{ok:false,reason:'invalid_email'}}];
await this.helpers.httpRequest({method:'POST',url:OJ_URL+'/rest/v1/events',
  headers:{...H,Prefer:'return=minimal'},
  body:{event_type:'oj_referral_optin',actor:'system',payload:{email,name,src:b.src||'refer_landing',note_email_state:'queued_pending_resend_key'}},json:true});
return [{json:{ok:true}}];
